    (`M lacks both the "override" modifier and the @Override annotation`),
    NOT {
      EXISTS (`functional expression mref`) {
        (`mref refers to method M`)
      }
    }
  }
}

Advisory/Deprecated Code/AvoidDeprecated.checker_dsl:
EXISTS (`call ca`, `callable c`) {
  AND {
    (`c is the source declaration of the callee of ca`),
    OR {
      (`c has a Deprecated annotation`),
      (`c has a Javadoc tag "@deprecated"`)
    },
    NOT {
      EXISTS (`callable caller`) {
        AND {
          (`caller is the caller of ca`),
          OR {
            (`caller has a Deprecated annotation`),
            (`caller has a Javadoc tag "@deprecated"`)
          }
        }
      }
    }
  }
}

Advisory/Documentation/SpuriousJavadocPa.checker_dsl:
EXISTS (`Javadoc param tag PT`) {
  AND {
    (`PT is a child of the Javadoc of a documentable element D`),
    OR {
      AND {
        (`PT has a parameter name`),
        OR {
          AND {
            (`D is a Callable (method or constructor)`),
            NOT { EXISTS (`parameter P of D`) {
              (`P's name equals PT's parameter name`)
            } },
            NOT { EXISTS (`type variable TV where TV's generic callable is D`) {
              (`"<" + TV's name + ">" equals PT's parameter name`)
            } }
          },
          AND {
            (`D is a ClassOrInterface`),
            NOT { (`D is a Record`) },
            NOT { EXISTS (`type variable TV where TV's generic type is D`) {
              (`"<" + TV's name + ">" equals PT's parameter name`)
            } }
          },
          AND {
            (`D is a Record`),
            NOT { EXISTS (`type variable TV where TV's generic type is D`) {
              (`"<" + TV's name + ">" equals PT's parameter name`)
            } },
            NOT { EXISTS (`parameter P of D's canonical constructor`) {
              (`P's name equals PT's parameter name`)
            } }
          }
        }
      },
      (`PT does not have a parameter name`)
    }
  }
}

Advisory/Documentation/ImpossibleJavadoc.checker_dsl:
EXISTS (`ThrowsTag throwsTag`, `ClassOrInterface thrownType`, `Callable docMethod`) {
  AND {
    EXISTS (`ImportType i`) {
      AND {
        (`i is in the same file as throwsTag`),
        (`i imports the type thrownType`),
        (`thrownType's name matches the exception name in throwsTag`)
      }
    },
    (`throwsTag is a descendant of the Javadoc of docMethod`),
    NOT { (`thrownType is an UncheckedThrowableType (e.g., RuntimeException or Error)`) },
    NOT {
      EXISTS (`Exception exception`) {
        AND {
          (`exception is declared in the throws clause of docMethod`),
          (`thrownType is a descendant of the type of exception`)
        }
      }
    }
  }
}

DeadCode/UselessParameter.ql.checker_dsl:
