  (`P has source node S and sink node K where S is an ActiveThreatModelSource, K has associated regular expression literal R, regular expression from R is matched against expression of K, there exists polynomial backtracking term T where T.getRootTerm() equals the regular expression term from K, P flows from S to K, and there does not exist barrier node B on path P where B is a SimpleTypeSanitizer or B's expression is method call M where M calls method methodDef where methodDef's lowercase name matches patterns: "%header%", "%requesturi%", "%requesturl%", "%cookie%" or methodDef's declaring type's lowercase name contains "%cookie%" and methodDef's name starts with "get" or methodDef's declaring type's lowercase name contains "%request%" and methodDef's lowercase name matches patterns: "%get%path%", "get%user%", "%querystring%"`)
}

Security/CWE/CWE-681/NumericCastTainted..checker_dsl:
EXISTS (`numeric narrowing cast expression NNC`) {
  AND {
    (`NNC is a CastExpr`),
    (`NNC has a source expression SRC_EXPR`),
    (`SRC_EXPR is a VarAccess`),
    EXISTS (`data flow source node SRC`, `data flow sink node SNK`) {
      AND {
        (`SRC is an instance of ActiveThreatModelSource`),
        (`SNK associated expression is SRC_EXPR`),
        (`there exists a taint flow path from SRC to SNK`),
        NOT {
          EXISTS (`data flow node N`) {
            OR {
              EXISTS (`SSA definition V`, `ConditionBlock CB`, `ComparisonExpr COMP`, `boolean TEST_IS_TRUE`) {
                AND {
                  (`N associated expression is a VarRead READ`),
                  (`READ equals V getARead`),
                  (`CB controls READ basic block with truth value TEST_IS_TRUE`),
                  (`CB condition is COMP`),
                  OR {
                    AND {
                      (`COMP lesser operand is V getARead`),
                      (`TEST_IS_TRUE equals true`)
                    },
                    AND {
                      (`COMP greater operand is V getARead`),
                      (`TEST_IS_TRUE equals false`)
                    }
                  }
                }
              },
              EXISTS (`EqualityTest EQ`, `CastExpr CAST`) {
                AND {
                  (`N associated expression is a VarRead READ`),
                  (`CAST expression is READ`),
                  (`EQ has operands CAST and READ variable an access`)
                }
              },
              (`N type is a SmallType`),
              EXISTS (`int LOW`, `int HIGH`) {
                AND {
                  (`N associated expression is bounded below by LOW with strictness false`),
                  (`N associated expression is bounded above by HIGH with strictness true`),
                  (`HIGH minus LOW less than 256`)
                }
              },
              (`N enclosing callable is a HashCodeMethod`),
              EXISTS (`right shift operation RSO`) {
                AND {
                  (`RSO is a RightShiftExpr UnsignedRightShiftExpr AssignRightShiftExpr or AssignUnsignedRightShiftExpr`),
                  OR {
                    (`RSO left-hand side is an access of a variable VAR`),
                    (`RSO left-hand side is an AndBitwiseExpr and one of its operands is an access of a variable VAR`)
                  },
                  (`N associated expression is an access of VAR`)
                }
              }
            }
          }
        }
      }
    }
  }
}

Security/CWE/CWE-078/ExecTainted.ql.checker_dsl:
EXISTS (`taint flow path P`) {
  EXISTS (`source node SRC`) {
    EXISTS (`sink node SNK`) {
      AND {
        (`SRC is an instance of ActiveThreatModelSource`),
        (`SNK is an instance of CommandInjectionSink`),
        (`P is a taint flow path from SRC to SNK`),
        NOT {
          EXISTS (`barrier node B`) {
            AND {
              (`B is an instance of CommandInjectionSanitizer`),
              (`B lies on the taint flow path P`)
            }
          }
        },
        (`execArg is an argument to a command execution method and is represented by the sink node SNK`)
      }
    }
  }
}

Security/CWE/CWE-780/RsaWithoutOaep.ql.checker_dsl:
EXISTS (`data flow source node SRC`, `data flow sink node SNK`) {
  AND {
    EXISTS (`compile-time constant expression SPEC_EXPR`, `string value SPEC`) {
      AND {
        (`SPEC_EXPR has string value SPEC`),
        (`SPEC_EXPR equals SRC as expression`),
        (`SPEC matches pattern "RSA/%"`),
        NOT { (`SPEC matches pattern "%OAEP%"`) }
      }
    },
    EXISTS (`cryptographic algorithm specification CR`) {
      (`SNK as expression equals CR.getAlgoSpec()`)
    },
    (`there exists a data flow path from SRC to SNK`)
  }
}

Security/CWE/CWE-552/UrlForward.ql.checker_dsl:
EXISTS (`taint flow path P`) {
  AND {
    EXISTS (`source node S`, `sink node T`) {
      AND {
        (`S is an ActiveThreatModelSource`),
        NOT {
          EXISTS (`method call MC`, `method M`) {
            AND {
              (`MC = S.asExpr()`),
              (`MC calls method M`),
              OR {
                (`M is HttpServletRequestGetRequestUriMethod`),
                (`M is HttpServletRequestGetRequestUrlMethod`),
                (`M is HttpServletRequestGetPathMethod`)
              }
            }
          }
        },
        OR {
          (`T is DefaultUrlForwardSink`),
          EXISTS (`SpringRequestMappingMethod SRMM`) {
            AND {
              (`SRMM polycalls T.getEnclosingCallable()`),
              EXISTS (`ForwardPrefix FP`) {
                AND {
                  (`T.asExpr() = FP.getAnAppendedExpression()`),
                  (`FP.getStringValue() = "forward:"`)
                }
              }
            }
          }
        },
        (`P is a taint flow path from S to T`),
        FORALL (`node N`) {
          NOT {
            OR {
              (`N is UrlPathBarrier`),
              EXISTS (`BarrierPrefix BP`) {
                AND {
                  (`N.asExpr() = BP.getAnAppendedExpression()`),
                  OR {
                    (`BP.getStringValue() contains "?" or "#" at position BP.offset`),
                    (`BP is CharacterLiteral with value "?" or "#" and BP.offset = 0`)
                  }
                }
              },
              EXISTS (`RedirectPrefix RP`) {
                AND {
                  (`N.asExpr() = RP.getAnAppendedExpression()`),
                  (`RP.getStringValue() = "redirect:"`)
                }
              },
              (`N is PrimitiveBarrier`),
              (`N is NoUrlEncodingBarrier`),
              EXISTS (`Variable V`, `Expr E`) {
                AND {
                  (`N.asExpr() = V.getAnAccess()`),
                  EXISTS (`CheckUrlEncodingGuard G`, `RepeatedUrlDecodeCall D`) {
                    AND {
                      (`E = G.getCheckedExpr()`),
                      (`G.controls(D.getBasicBlock(), true)`)
                    }
                  },
                  (`E = V.getAnAccess()`),
                  (`E.getBasicBlock().dominates(N.asExpr().getBasicBlock())`)
                }
              }
            }
          }
        }
      }
    }
  }
}

Security/CWE/CWE-089/SqlTainted.ql.checker_dsl:
EXISTS (`QueryInjectionSink QIS`) {
  EXISTS (`QueryInjectionFlow::PathNode sourcePathNode`, `QueryInjectionFlow::PathNode sinkPathNode`) {
    AND {
      (`the DataFlow::Node corresponding to sourcePathNode is an instance of the class ActiveThreatModelSource`),
      (`the DataFlow::Node corresponding to sinkPathNode is an instance of the class QueryInjectionSink`),
      (`the DataFlow::Node corresponding to sinkPathNode is the same element as the QueryInjectionSink QIS`)
    }
  }
}

Security/CWE/CWE-489/WebviewDebuggingEna.checker_dsl:
EXISTS (`data flow path P`) {
  AND {
    EXISTS (`source node SRC`, `sink node SNK`) {
      AND {
        (`SRC is a node on path P`),
        (`SNK is a node on path P`),
        (`path P flows from SRC to SNK`),
        EXISTS (`boolean literal expression BL`) {
          AND {
            (`BL is a BooleanLiteral`),
            (`BL has the value true`),
            (`SRC is the data flow node for expression BL`)
          }
        },
        EXISTS (`method call MC`) {
          AND {
            (`MC's called method has qualified name "android.webkit.WebView.setWebContentsDebuggingEnabled"`),
            (`MC has an argument at index 0`),
            (`SNK is the data flow node for the expression that is MC's argument at index 0`)
          }
        },
        NOT {
          EXISTS (`node N on path P`) {
            OR {
              EXISTS (`expression debug`, `string debugStr`) {
                AND {
                  (`debugStr converted to lowercase matches pattern "%debug%"`),
                  (`debugStr converted to lowercase matches pattern "%test%"`),
                  EXISTS (`sub-expression subex`) {
                    AND {
                      (`subex is a transitive parent (zero or more steps) of debug`),
                      EXISTS (`variable V`) {
                        AND {
                          (`subex is a VarAccess`),
                          (`V is the variable accessed by subex`),
                          (`V's name is debugStr`)
                        }
                      }
                    }
                  },
                  (`debug controls the basic block containing the expression of node N`)
                }
              },
              EXISTS (`callable C`, `type T`) {
                AND {
                  (`C encloses the expression of node N`),
                  (`T is the declaring type of C`),
                  (`T is an instance of NonSecurityTestClass`)
                }
              }
            }
          }
        }
      }
    }
  }
}

Security/CWE/CWE-074/XsltInjection.ql.checker_dsl:
EXISTS (`path P`) {
  AND {
    EXISTS (`source S`) {
      (`S is an instance of ActiveThreatModelSource`)
    },
    EXISTS (`sink T`) {
      (`T is an instance of XsltInjectionSink`)
    },
    (`P has source S`),
    (`P has sink T`),
    EXISTS (`node N1`, `node N2`) {
      AND {
        (`N1 and N2 are consecutive nodes in flow path P`),
        OR {
          (`standard taint tracking flow exists from N1 to N2`),
          EXISTS (`call MC`, `method M`) {
            AND {
              (`MC calls method M`),
              (`N1 as expression is an argument of MC`),
              (`N2 as expression is MC`),
              (`M is declared in a type that is an instance of TransformerFactory`),
              (`M has name newTransformer or newTemplates`),
              NOT {
                EXISTS (`expression E`) {
                  AND {
                    (`E is the qualifier of MC`),
                    (`TransformerFactoryWithSecureProcessingFeatureFlow::flowToExpr holds for E`)
                  }
                }
              }
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`node B`) {
        AND {
          (`B is an instance of SimpleTypeSanitizer`),
          (`B is in flow path P between S and T`)
        }
      }
    }
  }
}

Security/CWE/CWE-327/BrokenCryptoAlgorit.checker_dsl:
EXISTS (`path P`) {
  AND {
    EXISTS (`literal S`) {
      (`S is a ShortStringLiteral and its string value matches the insecure algorithm regex pattern and does not match "RSA/ECB.*" and does not match ".*\\p{IsLowercase} des \\p{IsLetter}.*"`)
    },
    EXISTS (`expression E`) {
      EXISTS (`call C`) {
        (`E equals C.getAlgoSpec()`)
      }
    },
    (`P has source node with expression S`),
    (`P has sink node with expression E`),
    EXISTS (`name N`, `string R`) {
      AND {
        OR {
          (`N equals "DES"`),
          (`N equals "RC2"`),
          (`N equals "RC4"`),
          (`N equals "ARCFOUR"`),
          (`N equals "RC5"`),
          (`N equals "ECB"`),
          (`N equals "AES/CBC/PKCS[57]Padding"`)
        },
        (`S's string value matches the regex pattern for algorithm name N`)
      }
    }
  }
}

Security/CWE/CWE-940/AndroidIntentRedire.checker_dsl:
EXISTS (`DataFlow::Node source`, `DataFlow::Node sink`) {
  AND {
    (`source is an instance of ActiveThreatModelSource`),
    (`sink is an instance of IntentRedirectionSink`),
    EXISTS (`DataFlow::Path p`) {
      AND {
        (`the taint flow follows the IntentRedirectionConfig configuration`),
        NOT { EXISTS (`DataFlow::Node barrier`) {
          AND {
            (`barrier is an instance of IntentRedirectionSanitizer`),
            (`barrier lies on the taint flow path between source and sink`),
            OR {
              (`barrier is not an instance of OriginalIntentSanitizer`),
              AND {
                (`barrier is an instance of OriginalIntentSanitizer`),
                (`SameIntentBeingRelaunchedFlow::flowTo(barrier) holds`)
              }
            }
          }
        } },
        FORALL (`DataFlow::Node node1`, `DataFlow::Node node2`) {
          (`if any IntentRedirectionAdditionalTaintStep c has step(node1, node2), then node2 is tainted from node1`)
        }
      }
    }
  }
}

Security/CWE/CWE-927/ImplicitPendingInte.checker_dsl:
EXISTS (`taint path TP`) {
  AND {
    EXISTS (`dataflow node sourceNode`) {
      AND {
        (`sourceNode is an instance of ImplicitPendingIntentSource`),
        (`the associated taint state for sourceNode is NoState`)
      }
    },
    EXISTS (`dataflow node sinkNode`) {
      AND {
        (`sinkNode is an instance of ImplicitPendingIntentSink`),
        (`the associated taint state for sinkNode is MutablePendingIntent`)
      }
    },
    EXISTS (`dataflow node barrierNode`) {
      (`barrierNode is an instance of ExplicitIntentSanitizer`)
    },
    NOT {
      EXISTS (`dataflow step barrierStep on path TP`) {
        (`barrierStep passes through barrierNode`)
      }
    },
    EXISTS (`dataflow step stateTransitionStep on path TP`) {
      AND {
        EXISTS (`dataflow node node1, dataflow node node2`) {
          AND {
            (`node1 and node2 are connected by mutablePendingIntentCreation from an ImplicitPendingIntentAdditionalTaintStep`),
            (`the state for node1 is NoState`),
            (`the state for node2 is MutablePendingIntent`)
          }
        }
      }
    },
    EXISTS (`dataflow step additionalStep on path TP`) {
      EXISTS (`dataflow node nodeA, dataflow node nodeB`) {
        (`nodeA and nodeB are connected by step from an ImplicitPendingIntentAdditionalTaintStep`)
      }
    },
    FORALL (`dataflow node implicitReadNode, dataflow content contentC on path TP where an implicit read occurs`) {
      OR {
        AND {
          (`implicitReadNode is a sink`),
          (`allowIntentExtrasImplicitRead holds for implicitReadNode and contentC`)
        },
        AND {
          (`implicitReadNode is part of an additional flow step`),
          (`contentC is a FieldContent`),
          (`the type of the field in contentC is PendingIntent`)
        },
        AND {
          OR {
            (`implicitReadNode is a sink`),
            (`implicitReadNode is part of a state-transition additional flow step`)
          },
          (`the type of implicitReadNode is an array`),
          (`the element type of the array of implicitReadNode is TypeIntent`),
          (`contentC is an ArrayContent`)
        }
      }
    }
  }
}

Security/CWE/CWE-113/ResponseSplitting.q.checker_dsl:
EXISTS (`taint flow path P`) {
  AND {
    EXISTS (`source node S`) {
      AND {
        (`S is an ActiveThreatModelSource`),
        NOT { (`S is a SafeHeaderSplittingSource`) }
      }
    },
    EXISTS (`sink node K`) {
      (`K is a HeaderSplittingSink`)
    },
    EXISTS (`barrier node B`) {
      OR {
        (`B is a SimpleTypeSanitizer`),
        EXISTS (`method call MC`, `compile-time constant expression CT`) {
          AND {
            (`B's expression equals MC`),
            (`MC calls a method from java.lang.String class`),
            (`CT is the first argument of MC`),
            OR {
              AND {
                (`MC's method name is "replace"`),
                OR {
                  (`CT's integer value equals 10`),
                  (`CT's integer value equals 13`)
                }
              },
              AND {
                (`MC's method name is "replaceAll"`),
                (`CT's string value matches regex pattern .*([\n\r]|\[\[\^[^\]\r\n]*\]).*`)
              }
            }
          }
        }
      }
    },
    (`P flows from S to K respecting barriers B`)
  }
}
